hooks.command:
node -e "
const input = JSON.parse(process.env.CLAUDE_TOOL_INPUT || '{}');
const path = input.file_path || input.path || '';
if (/production/i.test(path) || path.endsWith('.sql')) {
  console.error('BLOCKED: production パスまたは .sql ファイルへの書き込みはブロックされています: ' + path);
  process.exit(2);
}
"

node -e "
const input = JSON.parse(process.env.CLAUDE_TOOL_INPUT || '{}');
const path = input.file_path || input.path || '';
if (path.endsWith('.ts') || path.endsWith('.tsx')) {
  const { execSync } = require('child_process');
  try {
    execSync('npx prettier --write ' + JSON.stringify(path), { stdio: 'inherit' });
  } catch(e) {
    // prettier が未インストールの場合は静かに無視
  }
}
"
